:root {
  --bg: #f6f7f9;
  --card: #ffffff;
  --ink: #1c2430;
  --muted: #5b6675;
  --line: #e6e9ee;
  --accent: #0a6cff;
  --ok: #16a34a;
  --radius: 12px;
  --shadow: 0 1px 2px rgba(16, 24, 40, 0.05), 0 8px 24px rgba(16, 24, 40, 0.06);
}

* { box-sizing: border-box; }
html, body, #root { height: 100%; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--ink);
  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, Inter, Arial, sans-serif;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
}

.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 22px;
  background: var(--card);
  border-bottom: 1px solid var(--line);
  position: sticky;
  top: 0;
}

.brand { display: flex; align-items: center; gap: 10px; font-weight: 650; letter-spacing: 0.2px; }
.dot { width: 10px; height: 10px; border-radius: 50%; background: var(--accent); }

.pill { font-size: 12px; padding: 4px 10px; border-radius: 999px; border: 1px solid var(--line); color: var(--muted); }
.pill.ok { color: var(--ok); border-color: #bbf7d0; background: #f0fdf4; }
.pill.muted { background: #f8fafc; }

.container { max-width: 760px; margin: 28px auto; padding: 0 18px; display: grid; gap: 18px; }

.card {
  background: var(--card);
  border: 1px solid var(--line);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 22px 24px;
}

h1 { font-size: 24px; margin: 0 0 8px; }
h2 { font-size: 16px; margin: 0 0 14px; color: var(--muted); font-weight: 600; }
.lead { margin: 0; color: var(--muted); }

.row { display: flex; gap: 10px; margin-bottom: 14px; }
input {
  flex: 1;
  padding: 10px 12px;
  border: 1px solid var(--line);
  border-radius: 10px;
  font-size: 14px;
  outline: none;
}
input:focus { border-color: var(--accent); box-shadow: 0 0 0 3px rgba(10, 108, 255, 0.12); }

button {
  padding: 10px 16px;
  border: 0;
  border-radius: 10px;
  background: var(--accent);
  color: #fff;
  font-weight: 600;
  font-size: 14px;
  cursor: pointer;
}
button:hover { filter: brightness(1.05); }

.list { list-style: none; margin: 0; padding: 0; display: grid; gap: 8px; }
.list li { padding: 10px 12px; border: 1px solid var(--line); border-radius: 10px; background: #fcfdfe; }
.list li.empty { color: var(--muted); background: transparent; border-style: dashed; }

