                  <div key={i} className={`cal-cell ${flagged ? 'flag' : ''}`}>
                    <span className="cal-day">{d}</span>
                    <div className="cal-events">
                      {entries.map((e, j) => {
                        const p = patientsById[e.pid];
                        const t = TYPE_META[e.type];
                        return (
                          <div
                            key={j}
                            className={`ev ${t.cls}`}
                            title={`${p.name} (${p.id}) · ${e.type} · ${e.eye} · ${KASSEN[p.kasse].label}`}
                            onClick={() => setFocusPid(e.pid)}
                          >
                            <span className="ev-t">{t.label}</span>
                            <span className="ev-n">{p.name.split(' ')[0]}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="legend">
              {Object.values(TYPE_META).map((t) => (
                <span key={t.cls} className={`lg ${t.cls}`}>{t.label}</span>
              ))}
              <span className="lg flag-lg">Regelverstoss</span>
            </div>
          </section>

          {/* PATIENTENLISTE */}
          <section className="card">
            <h2>Patienten</h2>
            <ul className="plist">
              {PATIENTS.map((p) => {
                const cnt = errors.filter((f) => f.pid === p.id).length;
                const octN = APPOINTMENTS.filter(
                  (a) => a.pid === p.id && a.type === 'OCT' &&
                    new Date(a.d).getFullYear() === 2026
                ).length;
                return (
                  <li
                    key={p.id}
                    className={`${focusPid === p.id ? 'sel' : ''} ${cnt ? 'haserr' : ''}`}
                    onClick={() => setFocusPid(focusPid === p.id ? null : p.id)}
                  >
                    <div className="pl-main">
                      <strong>{p.name}</strong>
                      <span className="pl-id">{p.id}</span>
                    </div>
                    <span className="tag-kasse">{KASSEN[p.kasse].label}</span>
                    <span className={`pl-oct ${octN >= 6 ? 'full' : ''}`}>{octN}/6 OCT</span>
                    {cnt > 0 && <span className="pl-err">{cnt}</span>}
                  </li>
                );
              })}
            </ul>
          </section>
        </div>
      </main>
    </div>
  );
}

function fmt(d) {
  const dt = new Date(d);
  return dt.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: '2-digit' });
}

toolUseResult.originalFile:
import { useEffect, useState } from 'react';

// ============================================================================
//  STARTPUNKT-KOMPONENTE
//  Dieser Platzhalter beweist, dass Frontend <-> Backend lokal sauber laufen.
//  Im Slot wird dieser Inhalt durch den echten Prototyp ersetzt.
//  Regel: ausschliesslich synthetische Beispieldaten, NIE echte Patientendaten.
// ============================================================================
export default function App() {
  const [items, setItems] = useState([]);
  const [name, setName] = useState('');
  const [status, setStatus] = useState('lädt…');

  async function load() {
    try {
      const res = await fetch('/api/items');
      const data = await res.json();
      setItems(data.items || []);
      setStatus('Backend verbunden');
    } catch {
      setStatus('Frontend-only (kein Backend aktiv)');
    }
  }

  useEffect(() => {
    load();
  }, []);

  async function add(e) {
    e.preventDefault();
    if (!name.trim()) return;
    await fetch('/api/items', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: name.trim() }),
    });
    setName('');
    load();
  }

  return (
    <div className="page">
      <header className="topbar">
        <div className="brand">
          <span className="dot" />
          Prototyp-Startpunkt
        </div>
        <span className={`pill ${status === 'Backend verbunden' ? 'ok' : 'muted'}`}>{status}</span>
      </header>

      <main className="container">
        <section className="card">
          <h1>Hier entsteht dein Prototyp</h1>
          <p className="lead">
            Dieser Startpunkt zeigt, dass Frontend und Backend lokal sauber zusammenspielen.
            Ab hier wird live die Lösung gebaut – immer mit synthetischen Beispieldaten,
            niemals mit echten Patienten- oder Unternehmensdaten.
          </p>
        </section>

        <section className="card">
          <h2>Demo-Liste (Beispieldaten)</h2>
          <form className="row" onSubmit={add}>
            <input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Eintrag hinzufügen…"
              maxLength={80}
            />
            <button type="submit">Hinzufügen</button>
          </form>
          <ul className="list">
            {items.map((it) => (
              <li key={it.id}>{it.name}</li>
            ))}
            {items.length === 0 && <li className="empty">Noch keine Einträge.</li>}
          </ul>
        </section>
      </main>
    </div>
  );
}

